function containsBannedWord(text) {
  if (!text) return false;
  const lower = text.toLowerCase();
  return BLACKLIST.some(word => lower.includes(word.toLowerCase()));
}

function getMatchedWord(text) {
  if (!text) return null;
  const lower = text.toLowerCase();
  return BLACKLIST.find(word => lower.includes(word.toLowerCase())) || null;
}

module.exports = { BLACKLIST, containsBannedWord, getMatchedWord };
